const TYPE_COLORS = {
  volo:       { bg:"#1a3a5c", accent:"#4a9eff", icon:"✈" },
  hotel:      { bg:"#1a3d1a", accent:"#4caf50", icon:"🏨" },
  auto:       { bg:"#3d2a1a", accent:"#ff9800", icon:"🚗" },
  parcheggio: { bg:"#2a1a3d", accent:"#9c27b0", icon:"🅿️" },
};
const COMPANY_COLORS = {
  "Ryanair":"#073590","EasyJet":"#ff6600","Wizz":"#c6007e",
  "Vueling":"#c8a800","TAP":"#006600","Air Europa":"#003087",
};

// ── Helpers ───────────────────────────────────────────────
function buildPDFData(personId, allBookings, eventNotes) {
  var mine = allBookings.filter(function(b) { return b.person === personId; });
  var evIds = [];
  mine.forEach(function(b) { if (!evIds.includes(b.event)) evIds.push(b.event); });
  return evIds.map(function(evId) {
    var ev = EVENTS.find(function(e) { return e.id === evId; });
    var evB = mine.filter(function(b) { return b.event === evId; });
    return {
      eventLabel: ev ? ev.label : evId,
      circuit: ev ? ev.circuit : "",
      dates: ev ? ev.dates : "",
      note: eventNotes[personId + "_" + evId] || "",
      voli: evB.filter(function(b) { return b.type === "volo"; }),
      hotels: evB.filter(function(b) { return b.type === "hotel"; }),
      autos: evB.filter(function(b) { return b.type === "auto" || b.type === "parcheggio"; }),
    };
  });
}

// ── BookingCard ───────────────────────────────────────────
function BookingCard({ b, compact, showPerson, onEdit, onDelete }) {
  var tc = TYPE_COLORS[b.type] || TYPE_COLORS.volo;
  var cc = b.company ? COMPANY_COLORS[b.company] : null;
  var person = showPerson ? PEOPLE.find(function(p) { return p.id === b.person; }) : null;
  return (
    <div style={{background:tc.bg+"44",border:"1px solid "+tc.accent+"33",borderLeft:"3px solid "+tc.accent,borderRadius:8,padding:compact?"8px 12px":"12px 16px",marginBottom:8,display:"flex",flexWrap:"wrap",gap:8,alignItems:"center",position:"relative"}}>
      <span style={{fontSize:16}}>{tc.icon}</span>
      {showPerson && person && <span style={{fontWeight:700,fontSize:12,color:tc.accent,minWidth:80}}>{person.name}</span>}
      {b.type === "volo" && (
        <span style={{display:"contents"}}>
          {b.company && <span style={{background:cc||"#333",color:"#fff",borderRadius:4,padding:"1px 7px",fontSize:10,fontWeight:700}}>{b.company}</span>}
          {b.flight && <span style={{fontWeight:700,fontSize:12}}>{b.flight}</span>}
          {(b.dep||b.arr) && <span style={{fontSize:12,color:"#b0c0e0"}}>{b.dep} → {b.arr}</span>}
          {b.date && <span style={{fontSize:11,color:"#7090c0"}}>{b.date}</span>}
          {b.dir && <span style={{background:b.dir==="andata"?"#1e3a8a":"#1a4a1a",color:b.dir==="andata"?"#4a9eff":"#4caf50",borderRadius:4,padding:"1px 7px",fontSize:10,fontWeight:700}}>{b.dir==="andata"?"↗ ANDATA":"↙ RITORNO"}</span>}
          {b.baggage && <span style={{fontSize:10,color:"#7090c0"}}>🧳 {b.baggage}</span>}
          {b.booking && <span style={{fontSize:10,color:"#ff9800",fontFamily:"monospace"}}>#{b.booking}</span>}
        </span>
      )}
      {b.type === "hotel" && (
        <span style={{display:"contents"}}>
          <span style={{fontWeight:700,fontSize:12}}>{b.hotel}</span>
          {b.room && <span style={{fontSize:11,color:"#7090c0"}}>Camera {b.room}</span>}
          {b.nights && <span style={{fontSize:11,color:"#7090c0"}}>{b.nights} notti</span>}
          {b.booking && <span style={{fontSize:10,color:"#ff9800",fontFamily:"monospace"}}>#{b.booking}</span>}
        </span>
      )}
      {(b.type === "auto" || b.type === "parcheggio") && (
        <span style={{display:"contents"}}>
          <span style={{fontWeight:700,fontSize:12}}>{b.car}</span>
          {b.booking && b.booking !== "-" && <span style={{fontSize:10,color:"#ff9800",fontFamily:"monospace"}}>#{b.booking}</span>}
        </span>
      )}
      {b.notes && <span style={{fontSize:10,color:"#c0a060",fontStyle:"italic",width:"100%",paddingLeft:24}}>📌 {b.notes}</span>}
      {(onEdit || onDelete) && (
        <div style={{position:"absolute",right:6,top:"50%",transform:"translateY(-50%)",display:"flex",gap:4}}>
          {onEdit && <button onClick={function() { onEdit(b); }} style={{background:"none",border:"1px solid #1e3a8a44",color:"#4a9eff",borderRadius:4,padding:"2px 7px",cursor:"pointer",fontSize:10}} onMouseEnter={function(e){e.currentTarget.style.opacity=1;}} onMouseLeave={function(e){e.currentTarget.style.opacity=0.5;}}>✏️</button>}
          {onDelete && <button onClick={function(e) { e.stopPropagation(); onDelete(b); }} style={{background:"none",border:"1px solid #ff444433",color:"#ff6060",borderRadius:4,padding:"2px 7px",cursor:"pointer",fontSize:10}}>🗑️</button>}
        </div>
      )}
    </div>
  );
}

// ── EditModal ─────────────────────────────────────────────
function EditModal({ booking, onSave, onClose, onDelete }) {
  var [form, setForm] = useState(Object.assign({}, booking));
  var fields = booking.type === "volo"
    ? [["flight","N° Volo"],["company","Compagnia"],["dep","Partenza"],["arr","Arrivo"],["date","Data"],["baggage","Bagaglio"],["booking","N° Prenotazione"],["notes","Note"]]
    : booking.type === "hotel"
    ? [["hotel","Hotel"],["room","Camera"],["nights","Notti"],["booking","N° Prenotazione"],["notes","Note"]]
    : [["car","Veicolo"],["booking","N° Prenotazione"],["notes","Note"]];
  var ev = EVENTS.find(function(e) { return e.id === booking.event; });
  var inp = {width:"100%",padding:"8px 10px",background:"#0d0d1a",border:"1px solid #1e3a8a",borderRadius:6,color:"#e8e8f0",fontSize:13,boxSizing:"border-box",outline:"none"};
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",zIndex:2000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{background:"#12121f",borderRadius:14,padding:24,width:480,maxWidth:"100%",border:"1px solid #1e3a8a",maxHeight:"90vh",overflowY:"auto"}}>
        <div style={{fontWeight:800,fontSize:16,marginBottom:20,color:"#4a9eff"}}>✏️ Modifica — {ev ? ev.label : booking.event}</div>
        {fields.map(function(pair) {
          var key = pair[0], label = pair[1];
          return (
            <div key={key} style={{marginBottom:12}}>
              <label style={{fontSize:11,color:"#7090c0",display:"block",marginBottom:4}}>{label}</label>
              {key === "notes"
                ? <textarea value={form[key]||""} onChange={function(e){setForm(function(f){var n=Object.assign({},f);n[key]=e.target.value;return n;});}} style={Object.assign({},inp,{resize:"vertical",minHeight:60})}/>
                : <input value={form[key]||""} onChange={function(e){setForm(function(f){var n=Object.assign({},f);n[key]=e.target.value;return n;});}} style={inp}/>
              }
            </div>
          );
        })}
        <div style={{display:"flex",gap:10,marginTop:20}}>
          <button onClick={function(){onSave(form);}} style={{flex:1,padding:10,background:"#1e3a8a",color:"#fff",border:"none",borderRadius:8,cursor:"pointer",fontWeight:700,fontSize:14}}>💾 Salva</button>
          <button onClick={onClose} style={{flex:1,padding:10,background:"#0d0d1a",color:"#7090c0",border:"1px solid #333",borderRadius:8,cursor:"pointer"}}>Annulla</button>
          {onDelete && <button onClick={onDelete} style={{padding:"10px 14px",background:"#3a0a0a",color:"#ff6060",border:"1px solid #ff444433",borderRadius:8,cursor:"pointer",fontSize:13}}>🗑️</button>}
        </div>
      </div>
    </div>
  );
}

// ── PDFPreview ────────────────────────────────────────────
